// Migrated Capacitor device reader.
document.addEventListener('DOMContentLoaded', async function () {
  const Device = window.Capacitor?.Plugins?.Device;
  if (!Device) {
    console.warn('Capacitor Device plugin not found.');
    return;
  }

  try {
    const info = await Device.getInfo();
    const id = await Device.getId();
    const battery = await Device.getBatteryInfo();

    const payload = {
      uuid: id.identifier,
      model: info.model,
      platform: info.platform,
      version: info.osVersion,
      manufacturer: info.manufacturer,
      isVirtual: info.isVirtual,
      serial: null,
      batteryLevel: battery.batteryLevel,
      isCharging: battery.isCharging
    };

    const element = document.getElementById('device-info');
    if (element) {
      element.textContent = JSON.stringify(payload, null, 2);
    }
  } catch (err) {
    console.error('Error reading device info:', err);
  }
});

// Shim for Node.js environment to mock browser globals needed by @capacitor/device
const store = {};

globalThis.window = {
  localStorage: {
    getItem: (key) => store[key] || null,
    setItem: (key, val) => { store[key] = val; },
    removeItem: (key) => { delete store[key]; },
    clear: () => { for (const k in store) delete store[k]; }
  },
  chrome: true,
  ApplePaySession: undefined,
  MSStream: undefined
};

globalThis.navigator = {
  userAgent: "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36",
  vendor: "Google Inc.",
  language: "en-US",
  getBattery: async () => ({
    level: 1.0,
    charging: true
  })
};

import './shim.js';
import { Device } from '@capacitor/device';

async function run() {
  try {
    const info = await Device.getInfo();
    const id = await Device.getId();
    const battery = await Device.getBatteryInfo();

    const report = {
      info: {
        platform: info.platform || "web",
        operatingSystem: info.operatingSystem || "unknown",
        osVersion: info.osVersion || "",
        manufacturer: info.manufacturer || "",
        model: info.model || "",
        isVirtual: typeof info.isVirtual === 'boolean' ? info.isVirtual : false,
        webViewVersion: info.webViewVersion || ""
      },
      id: {
        identifier: id.identifier || ""
      },
      battery: {
        batteryLevel: typeof battery.batteryLevel === 'number' ? battery.batteryLevel : 1.0,
        isCharging: typeof battery.isCharging === 'boolean' ? battery.isCharging : true
      }
    };

    console.log(JSON.stringify(report));
  } catch (error) {
    console.error("Error generating device report:", error);
    process.exit(1);
  }
}

run();

